    69→  transcript_path: string;
    70→  hook_event_name: string;
    71→}
    72→
    73→interface RatingEntry {
    74→  timestamp: string;
    75→  rating: number;
    76→  comment?: string;
    77→  session_id: string;
    78→}
    79→
    80→/**
    81→ * Read stdin with timeout
    82→ */
    83→async function readStdinWithTimeout(timeout: number = 5000): Promise<string> {
    84→  return new Promise((resolve, reject) => {
    85→    let data = '';
    86→    const timer = setTimeout(() => reject(new Error('Timeout')), timeout);
    87→    process.stdin.on('data', (chunk) => { data += chunk.toString(); });
    88→    process.stdin.on('end', () => { clearTimeout(timer); resolve(data); });
    89→    process.stdin.on('error', (err) => { clearTimeout(timer); reject(err); });
    90→  });
    91→}
    92→
    93→/**
    94→ * CRITICAL: Precise rating detection
    95→ *
    96→ * Must match:
    97→ * - "7" (single number)
    98→ * - "8 - good work" (number + dash + comment)
    99→ * - "6: needs work" (number + colon + comment)
   100→ * - "9 excellent" (number + space + comment)
   101→ *
   102→ * Must NOT match:
   103→ * - "I have 7 items" (number in sentence)
   104→ * - "do step 7" (contextual number)
   105→ * - "7th thing" (ordinal)
   106→ */
   107→function parseRating(prompt: string): { rating: number; comment?: string } | null {
   108→  const trimmed = prompt.trim();
   109→
   110→  // Pattern: Start with single digit (1-10), optionally followed by separator and comment
   111→  const ratingPattern = /^(10|[1-9])(?:\s*[-:]\s*|\s+)?(.*)$/;
   112→
   113→  const match = trimmed.match(ratingPattern);
   114→  if (!match) return null;
   115→
   116→  const rating = parseInt(match[1], 10);
   117→  const comment = match[2]?.trim() || undefined;
   118→
