     1→/**
     2→ * VoiceNotification.ts - Voice Notification Handler
     3→ *
     4→ * PURPOSE:
     5→ * Sends completion messages to the voice server for TTS playback.
     6→ * Extracts the 🗣️ voice line from responses and sends to ElevenLabs via voice server.
     7→ *
     8→ * Pure handler: receives pre-parsed transcript data, sends to voice server.
     9→ * No I/O for transcript reading - that's done by orchestrator.
    10→ */
    11→
    12→import { existsSync, readFileSync, appendFileSync, mkdirSync } from 'fs';
    13→import { join } from 'path';
    14→import { paiPath } from '../lib/paths';
    15→import { getIdentity, type VoicePersonality } from '../lib/identity';
    16→import { getISOTimestamp } from '../lib/time';
    17→import { isValidVoiceCompletion, getVoiceFallback } from '../lib/response-format';
    18→import type { ParsedTranscript } from '../../skills/PAI/Tools/TranscriptParser';
    19→
    20→const DA_IDENTITY = getIdentity();
    21→
    22→// ElevenLabs voice notification payload
    23→interface ElevenLabsNotificationPayload {
    24→  message: string;
    25→  title?: string;
    26→  voice_enabled?: boolean;
    27→  voice_id?: string;
    28→  voice_settings?: {
    29→    stability: number;
    30→    similarity_boost: number;
    31→    style: number;
    32→    speed: number;
    33→    use_speaker_boost: boolean;
    34→  };
    35→  volume?: number;
    36→}
    37→
    38→interface VoiceEvent {
    39→  timestamp: string;
    40→  session_id: string;
    41→  event_type: 'sent' | 'failed' | 'skipped';
    42→  message: string;
    43→  character_count: number;
    44→  voice_engine: 'elevenlabs';
    45→  voice_id: string;
    46→  status_code?: number;
    47→  error?: string;
    48→}
    49→
    50→const VOICE_LOG_PATH = paiPath('MEMORY', 'VOICE', 'voice-events.jsonl');
    51→const CURRENT_WORK_PATH = paiPath('MEMORY', 'STATE', 'current-work.json');
    52→
    53→function getActiveWorkDir(): string | null {
    54→  try {
    55→    if (!existsSync(CURRENT_WORK_PATH)) return null;
    56→    const content = readFileSync(CURRENT_WORK_PATH, 'utf-8');
    57→    const state = JSON.parse(content);
    58→    if (state.work_dir) {
    59→      const workPath = paiPath('MEMORY', 'WORK', state.work_dir);
    60→      if (existsSync(workPath)) return workPath;
    61→    }
    62→  } catch {
    63→    // Silent fail
    64→  }
    65→  return null;
    66→}
    67→
    68→function logVoiceEvent(event: VoiceEvent): void {
    69→  const line = JSON.stringify(event) + '\n';
    70→
    71→  try {
    72→    const dir = paiPath('MEMORY', 'VOICE');
    73→    if (!existsSync(dir)) {
    74→      mkdirSync(dir, { recursive: true });
    75→    }
    76→    appendFileSync(VOICE_LOG_PATH, line);
    77→  } catch {
    78→    // Silent fail
    79→  }
    80→
    81→  try {
    82→    const workDir = getActiveWorkDir();
    83→    if (workDir) {
    84→      appendFileSync(join(workDir, 'voice.jsonl'), line);
    85→    }
    86→  } catch {
    87→    // Silent fail
    88→  }
    89→}
    90→
    91→async function sendNotification(payload: ElevenLabsNotificationPayload, sessionId: string): Promise<void> {
    92→  const voiceId = payload.voice_id || DA_IDENTITY.voiceId || 's3TPKV1kjDlVtZbl4Ksh';
    93→
    94→  const baseEvent: Omit<VoiceEvent, 'event_type' | 'status_code' | 'error'> = {
    95→    timestamp: getISOTimestamp(),
    96→    session_id: sessionId,
    97→    message: payload.message,
    98→    character_count: payload.message.length,
    99→    voice_engine: 'elevenlabs',
   100→    voice_id: voiceId,
   101→  };
   102→
   103→  try {
   104→    // Use ElevenLabs voice server /notify endpoint
   105→    const response = await fetch('http://localhost:8888/notify', {
   106→      method: 'POST',
   107→      headers: { 'Content-Type': 'application/json' },
   108→      body: JSON.stringify(payload),
   109→    });
   110→
   111→    if (!response.ok) {
   112→      console.error('[Voice] Server error:', response.statusText);
   113→      logVoiceEvent({
   114→        ...baseEvent,
   115→        event_type: 'failed',
   116→        status_code: response.status,
   117→        error: response.statusText,
